//go:build realhosts

// Package realhosts holds the real-host end-to-end tier: it drives the two
// standing worker machines (the amd64 edge behind a symmetric NAT and the
// aarch64 concentrator with a public inbound IP) over SSH. It is guarded by the
// dedicated `realhosts` build tag — FULLY SEPARATE from the netns `e2e` tag — so
// neither the default unprivileged `go build ./...` / `go test ./...` nor the
// privileged `-tags e2e` netns suite compiles or runs any of it.
//
// The tier is REPORT-ONLY: it executes commands on the real hosts and records
// their output (connectivity, uname/arch, and — in later tasks — a synced,
// freshly built wanbond binary). It gates nothing; the netns `e2e` fixture
// remains the authoritative pass/fail harness. It COMPLEMENTS that fixture by
// exercising the actual internet path between the real NAT and the real public
// endpoint.
//
// Invoke it only via the opt-in `just realhosts` target; it is never part of
// `just test` or CI.
package realhosts

//go:build realhosts

package realhosts

import (
	"context"
	"fmt"
	"strings"
)

// Provisioning targets. Go is pinned to the module's toolchain family; the
// family check (go1.26) tolerates patch drift while still installing the exact
// pinned patch when a fresh install is required.
const (
	goVersion       = "1.26.4"
	goVersionFamily = "go1.26"
	goInstallDir    = "/usr/local/go"
	goBin           = goInstallDir + "/bin/go"

	// tunnelIface is the TUN device name the wanbond daemon creates
	// (internal/device.defaultTUNName). The concentrator firewall step ACCEPTs
	// INPUT traffic arriving on it.
	tunnelIface = "wanbond0"

	// persistedRulesFile is where the netfilter-persistent / iptables-persistent
	// package stores the IPv4 ruleset it restores at boot. On OCI Ubuntu the boot
	// restore from this file is what silently drops any rule inserted only into
	// the runtime chain (defect D7), so the tunnel ACCEPT rule must be written
	// here to survive a reboot.
	persistedRulesFile = "/etc/iptables/rules.v4"
)

// Sentinels a remote predicate echoes so a genuine SSH-transport failure (which
// makes Runner.Run return an error) is distinguishable from a predicate that
// simply evaluated false (which prints sentinelMissing and exits 0).
const (
	sentinelPresent = "WANBOND_PRESENT"
	sentinelMissing = "WANBOND_MISSING"
)

// StepStatus is the outcome of one provisioning step.
type StepStatus string

const (
	// StatusAlreadyPresent means the step's precondition already held; nothing
	// was mutated.
	StatusAlreadyPresent StepStatus = "already-present"
	// StatusChanged means the step performed an install/insert to satisfy its
	// precondition.
	StatusChanged StepStatus = "changed"
)

// StepReport records what one provisioning step did.
type StepReport struct {
	Name   string
	Status StepStatus
}

// ProvisionReport aggregates every step's outcome for one host. A report with no
// Changed steps means the host was already fully provisioned (a re-run
// signalling idempotency).
type ProvisionReport struct {
	Host  Host
	Arch  string
	Steps []StepReport
}

// Changed reports whether any step mutated the host.
func (r ProvisionReport) Changed() bool {
	for _, s := range r.Steps {
		if s.Status == StatusChanged {
			return true
		}
	}
	return false
}

// String renders the per-step outcome for test logs.
func (r ProvisionReport) String() string {
	parts := make([]string, 0, len(r.Steps))
	for _, s := range r.Steps {
		parts = append(parts, fmt.Sprintf("%s=%s", s.Name, s.Status))
	}
	return fmt.Sprintf("%s (arch=%s): [%s]", r.Host.Role, r.Arch, strings.Join(parts, " "))
}

// ProvisionOpts selects host-specific provisioning behaviour.
type ProvisionOpts struct {
	// TunnelIface, when non-empty, ensures an iptables INPUT ACCEPT rule for the
	// named tunnel interface (concentrator only). Empty skips the firewall step
	// (the edge needs no such rule).
	TunnelIface string
}

// step is a single idempotent provisioning action: predicate is a shell
// expression that exits 0 iff the desired state already holds; install is run
// only when predicate is false, and predicate must hold afterwards.
type step struct {
	name      string
	predicate string
	install   string
}

// checkCmd wraps a predicate so the remote command always exits 0 and prints a
// sentinel, letting runStep tell "predicate false" apart from "SSH failed".
func checkCmd(predicate string) string {
	return fmt.Sprintf("if %s; then echo %s; else echo %s; fi", predicate, sentinelPresent, sentinelMissing)
}

// aptInstall is the install command for an apt package: refresh the index (an
// idempotent no-op on an up-to-date host) then install non-interactively.
func aptInstall(pkg string) string {
	return "sudo apt-get update -qq && sudo DEBIAN_FRONTEND=noninteractive apt-get install -y " + pkg
}

// goInstallCmd downloads the pinned Go tarball for goArch and unpacks it into
// /usr/local, replacing any prior install atomically enough for this tier.
func goInstallCmd(goArch string) string {
	tarball := fmt.Sprintf("go%s.linux-%s.tar.gz", goVersion, goArch)
	return strings.Join([]string{
		fmt.Sprintf("curl -fsSL https://go.dev/dl/%s -o /tmp/%s", tarball, tarball),
		fmt.Sprintf("sudo rm -rf %s", goInstallDir),
		fmt.Sprintf("sudo tar -C /usr/local -xzf /tmp/%s", tarball),
		fmt.Sprintf("rm -f /tmp/%s", tarball),
	}, " && ")
}

// detectGoArch maps `uname -m` to the GOARCH token Go's download naming uses.
func detectGoArch(ctx context.Context, r *Runner, host Host) (string, error) {
	res, err := r.Run(ctx, host, "uname -m")
	if err != nil {
		return "", err
	}
	switch m := strings.TrimSpace(res.Stdout); m {
	case "x86_64":
		return "amd64", nil
	case "aarch64", "arm64":
		return "arm64", nil
	default:
		return "", fmt.Errorf("%s (%s): unsupported machine arch %q", host.Role, host.target(), m)
	}
}

// runStep evaluates a step's predicate, installs only when it is unmet, and
// verifies the predicate holds afterwards. A false predicate yields
// StatusAlreadyPresent with no mutation; an install yields StatusChanged.
func runStep(ctx context.Context, r *Runner, host Host, s step) (StepReport, error) {
	present, err := r.Run(ctx, host, checkCmd(s.predicate))
	if err != nil {
		return StepReport{}, fmt.Errorf("%s: precondition check failed on %s: %w", s.name, host.target(), err)
	}
	if strings.Contains(present.Stdout, sentinelPresent) {
		return StepReport{Name: s.name, Status: StatusAlreadyPresent}, nil
	}

	if _, err := r.Run(ctx, host, s.install); err != nil {
		return StepReport{}, fmt.Errorf("%s: install failed on %s: %w", s.name, host.target(), err)
	}

	verify, err := r.Run(ctx, host, checkCmd(s.predicate))
	if err != nil {
		return StepReport{}, fmt.Errorf("%s: post-install check failed on %s: %w", s.name, host.target(), err)
	}
	if !strings.Contains(verify.Stdout, sentinelPresent) {
		return StepReport{}, fmt.Errorf("%s: precondition still unmet after install on %s", s.name, host.target())
	}
	return StepReport{Name: s.name, Status: StatusChanged}, nil
}

// Provision brings host to the wanbond real-host baseline idempotently: iperf3 +
// gcc installed (apt) and Go goVersionFamily at /usr/local/go, plus — when
// opts.TunnelIface is set (concentrator) — an INPUT ACCEPT rule for that tunnel
// interface, inserted at the head of the chain so it precedes OCI's default
// REJECT AND persisted to persistedRulesFile so it survives a reboot (defect
// D7: OCI Ubuntu restores that file at boot, silently dropping any runtime-only
// rule). Every step checks current state before mutating, so a second call on
// an already-provisioned host returns a report with Changed()==false.
func Provision(ctx context.Context, r *Runner, host Host, opts ProvisionOpts) (ProvisionReport, error) {
	report := ProvisionReport{Host: host}

	goArch, err := detectGoArch(ctx, r, host)
	if err != nil {
		return report, err
	}
	report.Arch = goArch

	steps := []step{
		{name: "iperf3", predicate: "command -v iperf3 >/dev/null 2>&1", install: aptInstall("iperf3")},
		{name: "gcc", predicate: "command -v gcc >/dev/null 2>&1", install: aptInstall("gcc")},
		{
			name:      "go",
			predicate: fmt.Sprintf("test -x %s && %s version | grep -q %s", goBin, goBin, goVersionFamily),
			install:   goInstallCmd(goArch),
		},
	}
	if opts.TunnelIface != "" {
		iface := opts.TunnelIface
		steps = append(steps,
			step{
				// The netfilter-persistent service (from the iptables-persistent
				// package) is what restores persistedRulesFile at boot; it must be
				// installed before the persist step below can save into that file.
				name:      "iptables-persistent",
				predicate: "command -v netfilter-persistent >/dev/null 2>&1",
				install:   aptInstall("iptables-persistent"),
			},
			step{
				name: "tunnel-firewall",
				// -C exits 0 iff the exact rule already exists.
				predicate: fmt.Sprintf("sudo iptables -C INPUT -i %s -j ACCEPT 2>/dev/null", iface),
				// -I inserts at position 1 (chain head), guaranteeing the ACCEPT
				// precedes OCI's appended (-A) REJECT rule.
				install: fmt.Sprintf("sudo iptables -I INPUT -i %s -j ACCEPT", iface),
			},
			step{
				// Persist the runtime rule so it survives a reboot (D7). The
				// predicate matches the canonical `iptables-save` form of the rule
				// (always emitted with -A) in persistedRulesFile, so once saved the
				// step is a no-op on re-run; the install snapshots the whole current
				// runtime chain — with the tunnel ACCEPT inserted by the step above —
				// into persistedRulesFile.
				name:      "tunnel-firewall-persist",
				predicate: fmt.Sprintf("sudo grep -q -- '-A INPUT -i %s -j ACCEPT' %s 2>/dev/null", iface, persistedRulesFile),
				install:   "sudo netfilter-persistent save",
			},
		)
	}

	for _, s := range steps {
		sr, err := runStep(ctx, r, host, s)
		if err != nil {
			return report, err
		}
		report.Steps = append(report.Steps, sr)
	}
	return report, nil
}

// TunnelFirewallState is the concentrator INPUT-chain state relevant to the
// tunnel ACCEPT rule, as parsed from `iptables -S INPUT`.
type TunnelFirewallState struct {
	// AcceptCount is the number of `-i <iface> -j ACCEPT` rules in INPUT.
	AcceptCount int
	// BeforeReject is true iff the first such ACCEPT rule precedes the first
	// `-j REJECT` rule in the chain.
	BeforeReject bool
	// Persisted is true iff persistedRulesFile carries the tunnel ACCEPT rule,
	// i.e. the rule will survive a reboot (defect D7). A runtime-only rule
	// (Persisted==false) is silently dropped on the next boot.
	Persisted bool
	// Rules is the raw `iptables -S INPUT` output for diagnostics.
	Rules []string
}

// InspectTunnelFirewall reads host's INPUT chain and reports how many tunnel
// ACCEPT rules exist, whether the first precedes the REJECT rule, and whether
// the rule is persisted to persistedRulesFile (reboot-survivable).
func InspectTunnelFirewall(ctx context.Context, r *Runner, host Host, iface string) (TunnelFirewallState, error) {
	res, err := r.Run(ctx, host, "sudo iptables -S INPUT")
	if err != nil {
		return TunnelFirewallState{}, fmt.Errorf("%s (%s): iptables -S INPUT failed: %w", host.Role, host.target(), err)
	}

	lines := strings.Split(res.Stdout, "\n")
	state := TunnelFirewallState{Rules: lines}
	firstAccept, firstReject := -1, -1
	acceptNeedle := fmt.Sprintf("-i %s ", iface)
	for i, line := range lines {
		l := strings.TrimSpace(line)
		if strings.Contains(l, acceptNeedle) && strings.HasSuffix(l, "-j ACCEPT") {
			state.AcceptCount++
			if firstAccept == -1 {
				firstAccept = i
			}
		}
		if strings.Contains(l, "-j REJECT") && firstReject == -1 {
			firstReject = i
		}
	}
	state.BeforeReject = firstAccept != -1 && firstReject != -1 && firstAccept < firstReject

	// Persistence: the tunnel ACCEPT rule must be present in persistedRulesFile
	// (in its canonical `iptables-save` -A form) to survive a reboot. checkCmd
	// keeps a false predicate distinguishable from an SSH-transport failure.
	persistCheck := checkCmd(fmt.Sprintf("sudo grep -q -- '-A INPUT -i %s -j ACCEPT' %s 2>/dev/null", iface, persistedRulesFile))
	pres, err := r.Run(ctx, host, persistCheck)
	if err != nil {
		return state, fmt.Errorf("%s (%s): persisted-rule check failed: %w", host.Role, host.target(), err)
	}
	state.Persisted = strings.Contains(pres.Stdout, sentinelPresent)
	return state, nil
}

//go:build realhosts

package realhosts

import (
	"bytes"
	"context"
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
	"time"
)

// Environment variables that select the real hosts and credentials. Each has a
// default (below) so the tier runs against the standing worker machines with no
// configuration.
const (
	envEdgeHost  = "WANBOND_EDGE_HOST"
	envConcHost  = "WANBOND_CONC_HOST"
	envConcPubIP = "WANBOND_CONC_PUBLIP"
	envSSHKey    = "WANBOND_SSH_KEY"
)

// Defaults for the standing two-machine testbed:
//   - the edge sits behind a symmetric NAT and is amd64;
//   - the concentrator is aarch64 and has a public, inbound-reachable IP.
const (
	defaultEdgeHost  = "llm-ubuntu-0.pgtr.7mind.io"
	defaultConcHost  = "o3.7mind.io"
	defaultConcPubIP = "89.168.124.91"
	defaultSSHKey    = "/run/agenix/llm-ssh-key"

	// defaultUser is the login shared by both worker machines.
	defaultUser = "ubuntu"

	// defaultConnectTimeout bounds the TCP+auth handshake of a single ssh
	// invocation. The runner passes it as `-o ConnectTimeout=<n>` (seconds).
	defaultConnectTimeout = 10 * time.Second
)

// Host is one real machine reachable over SSH.
type Host struct {
	// Role is a human label for the machine's function ("edge"/"concentrator").
	Role string
	// Addr is the SSH target hostname (or IP) passed to ssh.
	Addr string
	// User is the SSH login user.
	User string
}

// target renders the user@host argument ssh expects.
func (h Host) target() string { return h.User + "@" + h.Addr }

// Config is the resolved real-host topology plus SSH credentials, populated from
// the environment (with defaults) by LoadConfig.
type Config struct {
	Edge Host
	Conc Host
	// ConcPubIP is the concentrator's public, inbound-reachable IP. The edge
	// (behind symmetric NAT) dials this; recorded here for later tasks.
	ConcPubIP string
	// SSHKey is the private-key path handed to `ssh -i`.
	SSHKey string
	// ConnectTimeout bounds each ssh connect.
	ConnectTimeout time.Duration
}

// envOr returns the value of env var key, or def when it is unset or empty.
func envOr(key, def string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return def
}

// LoadConfig resolves the real-host topology from the environment, applying the
// standing-testbed defaults for any unset variable. Both hosts use the default
// SSH login user.
func LoadConfig() Config {
	return Config{
		Edge:           Host{Role: "edge", Addr: envOr(envEdgeHost, defaultEdgeHost), User: defaultUser},
		Conc:           Host{Role: "concentrator", Addr: envOr(envConcHost, defaultConcHost), User: defaultUser},
		ConcPubIP:      envOr(envConcPubIP, defaultConcPubIP),
		SSHKey:         envOr(envSSHKey, defaultSSHKey),
		ConnectTimeout: defaultConnectTimeout,
	}
}

// Result captures the outcome of one remote command.
type Result struct {
	Host   Host
	Cmd    string
	Stdout string
	Stderr string
}

// Runner executes commands on real hosts over SSH. It is safe for sequential
// use; the SSH invocation itself carries no shared state.
type Runner struct {
	key            string
	connectTimeout time.Duration
}

// NewRunner builds a Runner from a Config's key and connect timeout.
func NewRunner(cfg Config) *Runner {
	return &Runner{key: cfg.SSHKey, connectTimeout: cfg.ConnectTimeout}
}

// sshArgs assembles the argv for a single ssh invocation against host running
// remoteCmd. The system ssh_config is known-broken on these workers, so `-F
// none` forces ssh to ignore it; the remaining options pin the identity file,
// auto-accept the host key on first contact, and bound the connect.
func (r *Runner) sshArgs(host Host, remoteCmd string) []string {
	secs := int(r.connectTimeout / time.Second)
	if secs < 1 {
		secs = 1
	}
	return []string{
		"-F", "none",
		"-i", r.key,
		"-o", "StrictHostKeyChecking=accept-new",
		"-o", "ConnectTimeout=" + strconv.Itoa(secs),
		host.target(),
		remoteCmd,
	}
}

// Run executes remoteCmd on host over SSH, capturing stdout and stderr
// separately. A non-nil error wraps the exit status and includes the captured
// stderr for diagnosis; ctx bounds the whole invocation.
func (r *Runner) Run(ctx context.Context, host Host, remoteCmd string) (Result, error) {
	cmd := exec.CommandContext(ctx, "ssh", r.sshArgs(host, remoteCmd)...)
	var stdout, stderr bytes.Buffer
	cmd.Stdout, cmd.Stderr = &stdout, &stderr

	res := Result{Host: host, Cmd: remoteCmd}
	err := cmd.Run()
	res.Stdout, res.Stderr = strings.TrimRight(stdout.String(), "\n"), strings.TrimRight(stderr.String(), "\n")
	if err != nil {
		return res, fmt.Errorf("ssh %s: %q: %w\nstderr: %s", host.target(), remoteCmd, err, res.Stderr)
	}
	return res, nil
}

